          codeBlock: '# Start Ollama manually\nollama serve\n\n# On Linux вҖ” restart the systemd service\nsystemctl restart ollama\n\n# Verify it is running\ncurl http://localhost:11434\n# Expected: "Ollama is running"',
          codeLanguage: 'bash',
